  ('medical-tech-moex-04608', 'medical-tech', 'medical-tech-moex-111-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '致癌基因的基因擴增（amplification）常是造成癌症的重要因素，下列何種方法最不適合應用於檢驗「基因擴 增」？', '["螢光原位雜交法（FISH）", "即時定量聚合酶連鎖反應（Real-time Q-PCR）", "次世代定序（Next-generation sequencing, NGS）", "桑格定序法 （Sanger sequencing）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:20+00:00", "source_pdf_sha1": "8b19c38cd34e", "answer_pdf_sha1": "1a485e4af2a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "111", "exam_name": "111年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 77, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
